class Solution:
    def maxUniqueSplit(self, s):
        n = len(s)
        best = 0
        for mask in range(1 << (n - 1)):
            parts = []
            start = 0
            for bit in range(n - 1):
                if mask & (1 << bit):
                    parts.append(s[start:bit + 1])
                    start = bit + 1
            parts.append(s[start:n])
            if len(set(parts)) == len(parts):
                best = max(best, len(parts))
        return best

