class Solution:
    def maxUniqueSplit(self, s):
        n = len(s)
        best = 0
        seen = set()

        def backtrack(i):
            nonlocal best
            if i == n:
                best = max(best, len(seen))
                return
            for j in range(i + 1, n + 1):
                piece = s[i:j]
                if piece in seen:
                    continue
                seen.add(piece)
                backtrack(j)
                seen.discard(piece)

        backtrack(0)
        return best

