var maxUniqueSplit = function(s) {
    const n = s.length;
    let best = 0;
    const seen = new Set();

    function backtrack(i) {
        if (i === n) {
            best = Math.max(best, seen.size);
            return;
        }
        for (let j = i + 1; j <= n; j++) {
            const piece = s.slice(i, j);
            if (seen.has(piece)) continue;
            seen.add(piece);
            backtrack(j);
            seen.delete(piece);
        }
    }

    backtrack(0);
    return best;
};
